'use client'

import { useEffect } from 'react'
import { useRouter } from 'next/navigation'
import { useAuth } from './providers/AuthProvider'

export default function Home() {
  const router = useRouter()
  const { user, loading } = useAuth()

  useEffect(() => {
    if (!loading) {
      if (user) {
        // Redireciona para a área correta baseado no role
        router.push(`/${user.role === 'admin' ? 'admin' : user.role === 'professor' ? 'professores' : 'alunos'}`)
      } else {
        // Sem usuário, vai para login
        router.push('/login')
      }
    }
  }, [user, loading, router])

  return (
    <div className="flex min-h-screen items-center justify-center bg-gradient-to-br from-red-50 to-orange-50">
      <div className="text-center">
        <div className="inline-block animate-spin rounded-full h-12 w-12 border-4 border-red-500 border-t-transparent mb-4"></div>
        <p className="text-gray-600">Carregando Nipo School...</p>
      </div>
    </div>
  )
}
